import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { User } from '../../models/models';

@Component({
  selector: 'app-navbar',
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.css']
})
export class NavbarComponent implements OnInit {
  currentUser: User | null = null;
  isMenuOpen = false;

  constructor(
    private authService: AuthService,
    private router: Router
  ) { }

  ngOnInit(): void {
    this.authService.currentUser.subscribe(user => {
      this.currentUser = user;
    });
  }

  get isAdmin(): boolean {
    return this.authService.isAdmin;
  }

  toggleMenu(): void {
    this.isMenuOpen = !this.isMenuOpen;
  }

  logout(): void {
    this.authService.logout();
  }
}
<nav class="navbar">
  <div class="nav-container">
    <div class="nav-brand" routerLink="/">
      <span class="logo">🗳️</span>
      <span class="brand-name">Voting System</span>
    </div>

    <button class="nav-toggle" (click)="toggleMenu()">
      <span></span>
      <span></span>
      <span></span>
    </button>

    <div class="nav-menu" [class.active]="isMenuOpen">
      <a routerLink="/" routerLinkActive="active" [routerLinkActiveOptions]="{exact: true}" class="nav-link">
        Home
      </a>

      <a routerLink="/elections" routerLinkActive="active" class="nav-link">
        Elections
      </a>

      <a *ngIf="isAdmin" routerLink="/admin" routerLinkActive="active" class="nav-link">
        Admin Dashboard
      </a>

      <div class="nav-user">
        <span class="user-name">{{ currentUser?.username }}</span>
        <span class="user-role" [class.admin]="isAdmin">{{ currentUser?.role }}</span>
        <button class="btn-logout" (click)="logout()">Logout</button>
      </div>
    </div>
  </div>
</nav>
